SELECT Orders_Actual.Post_P2_ID, Orders_Actual.Order_ID_Sub, Orders_Actual.Product_ID, Orders_Actual.Quantity, Orders_Actual.Price, Orders_Actual.Printer, Orders_Actual.Order_ID, IIf(([Include_Group]=False),[Products].[Description],[productGroups].[Description] & " " & [Products].[Description]) AS prDescription
FROM (Orders_Actual LEFT JOIN Products ON Orders_Actual.Product_ID = Products.Product_ID) LEFT JOIN ProductGroups ON Products.ProductGroup_ID = ProductGroups.ProductGroup_ID
ORDER BY Orders_Actual.Post_P2_ID;

SELECT Posts_Main.Post_ID, Posts_Main.Description, Orders.Order_ID, Orders.Clerk_ID, Orders.Time_Date, Orders.Order_Total, Posts_Main.Post_Number, Staff.Name, Staff.SurName, Orders.History, Orders.Closed, Orders.Order_Type, Orders.Order_Total_AfterD, Orders.Order_Discount_Amount
FROM (Posts_Main RIGHT JOIN Orders ON Posts_Main.Post_ID = Orders.Post_ID) LEFT JOIN Staff ON Orders.Clerk_ID = Staff.Staff_ID
WHERE (((Orders.Closed)=False) AND ((Orders.Order_Type)<>"Take Away" And (Orders.Order_Type)<>"Bar") AND ((Orders.Order_Total_AfterD)>0));

DELETE Order_Extras_Sub.*, Order_Extras_Sub.Order_ID_Sub
FROM Order_Extras_Sub
WHERE (((Order_Extras_Sub.Order_ID_Sub)=[Forms]![Order_Actual]![A_SubO_ID]));

DELETE Orders_Actual.*, Orders_Actual.Order_ID
FROM Orders_Actual
WHERE (((Orders_Actual.Order_ID)=[Forms]![Order_Actual]![Order_ID]));

DELETE Orders.*, Orders.Order_ID
FROM Orders
WHERE (((Orders.Order_ID)=[Forms]![Order_Actual]![Order_ID]));

SELECT DISTINCT Price_Catalogue_Sub.Price, Products.Menu_Number AS Sort, Product_Extra_Relation.Product_ID, Products.Description, Product_Extra_Relation.Extra_ID_Key, Products.Icon_ID, Price_Catalogue_Sub.Catalog_ID, Products.Description2
FROM (Product_Extra_Relation LEFT JOIN Products ON Product_Extra_Relation.Extra_ID_Key = Products.Product_ID) LEFT JOIN Price_Catalogue_Sub ON Products.Product_ID = Price_Catalogue_Sub.Product_ID
ORDER BY Price_Catalogue_Sub.Price, Products.Menu_Number;

SELECT DISTINCT Price_Catalogue_Sub.Price, Nz([Menu_Number],0) AS Sort, Grp_Relation_Extra.GroupID, Products.Description, Grp_Relation_Extra.Extra_ID_Key, Products.Icon_ID, Price_Catalogue_Sub.Catalog_ID, Products.ProductGroup_ID, Products.Description2
FROM Grp_Relation_Extra LEFT JOIN (Products LEFT JOIN Price_Catalogue_Sub ON Products.Product_ID = Price_Catalogue_Sub.Product_ID) ON Grp_Relation_Extra.Extra_ID_Key = Products.Product_ID
ORDER BY Price_Catalogue_Sub.Price, Nz([Menu_Number],0);

SELECT Orders.*, Posts_Main.Description, Yper_Posts.Yper_Description, Posts_Main.Active, Orders.History, Posts_Main.Active_Order_ID, Posts_Main.Post_Number, Names.Name AS Named
FROM ((Orders LEFT JOIN Posts_Main ON Orders.Post_ID = Posts_Main.Post_ID) LEFT JOIN Yper_Posts ON Posts_Main.Yper_Main_ID = Yper_Posts.Yper_Main_ID) LEFT JOIN [Names] ON Orders.Name_ID = Names.Name_ID
WHERE (((Orders.History)=False));

DELETE Product_Favorites.*, Product_Favorites.Product_ID
FROM Product_Favorites
WHERE (((Product_Favorites.Product_ID)=[forms]![Favorites]![Favorites]));

SELECT Users_Posts.Staff_ID, Posts_Main.Yper_Main_ID, Posts_Main.Post_ID, Posts_Main.Description, Posts_Main.Post_Number, Posts_Main.Active, Posts_Main.HeeftPool, Posts_Main.Reserve, Posts_Main.Name_Reserve, Posts_Main.Time, Posts_Main.CheckIn_Time, Posts_Main.Split, Posts_Main.SortNumber, Posts_Main.Clerk_ID, Posts_Main.Active_Order_ID, Posts_Main.Icon_ID, Posts_Main.Icon_ID_Occu
FROM Users_Posts LEFT JOIN Posts_Main ON Users_Posts.Post_ID = Posts_Main.Post_ID
ORDER BY Users_Posts.Staff_ID;

SELECT Top_Sellers.SumOfQuantity, IIf(([Include_Group]=False),[Products].[Description],[productGroups].[Description] & " " & [Products].[Description]) AS Description, Top_Sellers.Price, Top_Sellers.Product_Type, Top_Sellers.Unit, Top_Sellers.ProductGroup_ID, Top_Sellers.Printer, Top_Sellers.VAT, Top_Sellers.Build, Top_Sellers.Extra_ID, Top_Sellers.Row_Print, Top_Sellers.Icon_ID, Top_Sellers.Auto_Extra, Top_Sellers.Has_Options, Top_Sellers.Extra_ID_Key, Top_Sellers.Picture_Path, Top_Sellers.Recipe_ID, Top_Sellers.Menu_Number, Top_Sellers.Product_ID, Top_Sellers.Sale_Lock, Top_Sellers.Portion_Count
FROM Top_Sellers LEFT JOIN ProductGroups ON Top_Sellers.ProductGroup_ID = ProductGroups.ProductGroup_ID
ORDER BY Top_Sellers.SumOfQuantity DESC;
